public static ETGVendInvoiceDocumentController construct()
{
    return new ETGVendInvoiceDocumentController();

}

public static void main(Args _args)

{

    ETGVendInvoiceDocumentController controller = new ETGVendInvoiceDocumentController();

    controller.parmArgs(_args);

    controller.parmReportName(ssrsReportStr(ETGVendInvoiceDocument, ETGPurchInvoice));

    controller.parmShowDialog(false);

    controller.parmDialogCaption("Show Invoice");

    controller.startOperation();

}
